package com.ichi2.libanki

import anki.import_export.ExportLimit
import androidx.test.ext.junit.runners.AndroidJUnit4
import com.ichi2.testutils.JvmTest
import org.junit.Test
import org.junit.runner.RunWith
import java.io.File
import kotlin.test.assertTrue

/**
 * Test for verifying the Anki 23.12 backend integration with exportAnkiPackage.
 */
@RunWith(AndroidJUnit4::class)
class BackendImportExportTest : JvmTest() {

    /**
     * Test that exportAnkiPackage can be called with the new backend API.
     * This test verifies that the function signature is compatible and the
     * options builder pattern is correctly implemented.
     */
    @Test
    fun testExportAnkiPackageWithNewBackend() = runTest {
        val col = col
        val tempFile = File.createTempFile("test_export", ".apkg")
        try {
            tempFile.deleteOnExit()

            // Test with default legacy parameter
            col.exportAnkiPackage(
                outPath = tempFile.absolutePath,
                withScheduling = true,
                withMedia = false,
                limit = ExportLimit.getDefaultInstance()
            )

            assertTrue(tempFile.exists(), "Export file should be created")
            assertTrue(tempFile.length() > 0, "Export file should not be empty")
        } finally {
            tempFile.delete()
        }
    }

    /**
     * Test exportAnkiPackage with explicit legacy parameter.
     */
    @Test
    fun testExportAnkiPackageWithLegacyParameter() = runTest {
        val col = col
        val tempFile = File.createTempFile("test_export_legacy", ".apkg")
        try {
            tempFile.deleteOnExit()

            // Test with explicit legacy = false
            col.exportAnkiPackage(
                outPath = tempFile.absolutePath,
                withScheduling = false,
                withMedia = false,
                limit = ExportLimit.getDefaultInstance(),
                legacy = false
            )

            assertTrue(tempFile.exists(), "Export file should be created")
            assertTrue(tempFile.length() > 0, "Export file should not be empty")
        } finally {
            tempFile.delete()
        }
    }
}
